interface ButtonProps {
  label: string
  onClick: () => void
}

function Button({ label, onClick }: ButtonProps) {
  return <button onClick={onClick}>{label}</button>
}

const el = <Button label="Сохранить" onClick={() => save()} />

// TypeScript ищет 'Button' в текущей области видимости
// Находит: function Button({ label, onClick }: ButtonProps)
// Это функция → функциональный компонент
// Props = первый аргумент = ButtonProps

// Переданные атрибуты:
//   label: "Сохранить"   → string ✅ (ожидается string)
//   onClick: () => save() → () => void ✅ (ожидается () => void)

// Все обязательные пропсы присутствуют ✅
// Лишних пропсов нет ✅

// Результат выражения <Button ... /> имеет тип JSX.Element
const el = <Button label="Сохранить" onClick={() => save()} />
//    ^? const el: JSX.Element

// JSX.Element определён в @types/react:
// namespace JSX {
//   interface Element extends React.ReactElement<any, any> {}
// }
